function extractCustomSettings($node) {
    $result = [];
    
    foreach ($node->children() as $child) {
        $name = $child->getName();
        
        // Check if node has children
        if ($child->count() > 0) {
            $result[$name] = extractCustomSettings($child);
        } else {
            // Check for attributes
            $attributes = [];
            foreach ($child->attributes() as $attrName => $attrValue) {
                $attributes[$attrName] = (string)$attrValue;
            }
            
            if (count($attributes) > 0) {
                $result[$name] = [
                    'value' => (string)$child,
                    'attributes' => $attributes
                ];
            } else {
                $result[$name] = (string)$child;
            }
        }
    }
    
    return $result;
}

function validateConfigurationSettings($settings) {
    $errors = [];
    
    // Validate database settings
    if (isset($settings['database'])) {
        if (empty($settings['database']['host'])) {
            $errors[] = 'Database host is required';
        }
        if (empty($settings['database']['name'])) {
            $errors[] = 'Database name is required';
        }
    }
    
    // Validate application settings
    if (isset($settings['application'])) {
        if (empty($settings['application']['name'])) {
            $errors[] = 'Application name is required';
        }
        $validEnvironments = ['development', 'staging', 'production'];
        if (!in_array($settings['application']['environment'], $validEnvironments)) {
            $errors[] = 'Invalid environment value';
        }
    }
    
    // Validate email settings
    if (isset($settings['email']) && $settings['email']['driver'] === 'smtp') {
        if (empty($settings['email']['host'])) {
            $errors[] = 'Email host is required for SMTP driver';
        }
    }
    
    // Validate security settings
    if (isset($settings['security'])) {
        if (empty($settings['security']['encryption_key'])) {
            $errors[] = 'Encryption key is required';
        }
    }
    
    return [
        'valid' => count($errors) === 0,
        'errors' => $errors
    ];
}

function saveConfiguration($settings, $configPath) {
    $configContent = "<?php\n\nreturn " . var_export($settings, true) . ";\n";
    return file_put_contents($configPath, $configContent) !== false;
}

